# Production-scale multi-agent cricket scoring system
import asyncio
from dataclasses import dataclass
from enum import Enum
from typing import Optional

class MatchPhase(Enum):
    POWERPLAY = "powerplay"  # Overs 1-6
    MIDDLE = "middle"  # Overs 7-15
    DEATH = "death"  # Overs 16-20

@dataclass
class CricketMatchState:
    innings: int
    overs: int
    runs: int
    wickets: int
    current_phase: MatchPhase
    tokens_used: int = 0
    max_tokens: int = 8192

class BattingAgent:
    """Agent that decides batting strategy based on match state."""
    async def decide_strategy(self, state: CricketMatchState) -> dict:
        if state.tokens_used > state.max_tokens * 0.8:
            return {"strategy": "finalize", "tokens_warning": True}

        if state.current_phase == MatchPhase.POWERPLAY:
            return {"strategy": "aggressive", "target_scoring_rate": 8.0}
        elif state.current_phase == MatchPhase.DEATH:
            return {"strategy": "maximize_boundaries", "target_scoring_rate": 12.0}
        else:
            return {"strategy": "build_partnership", "target_scoring_rate": 6.5}

class FieldingAgent:
    """Agent coordinating field placement and bowling strategy."""
    async def recommend_field(self, state: CricketMatchState, batting_style: dict) -> dict:
        if batting_style["strategy"] == "aggressive":
            return {"field_type": "attacking", "slips": 2, "deep_fielders": 3}
        else:
            return {"field_type": "defensive", "slips": 0, "deep_fielders": 5}

class MatchOrchestrator:
    """Central orchestrator managing agent coordination and state."""
    def __init__(self):
        self.batting_agent = BattingAgent()
        self.fielding_agent = FieldingAgent()
        self.state = CricketMatchState(
            innings=1, overs=0, runs=0, wickets=0,
            current_phase=MatchPhase.POWERPLAY
        )

    async def execute_over(self) -> dict:
        """Execute one over with coordinated agent decisions."""
        # Batting agent decides strategy
        batting_decision = await self.batting_agent.decide_strategy(self.state)
        self.state.tokens_used += 150  # Simulate token consumption

        if batting_decision.get("tokens_warning"):
            return {"status": "token_budget_exceeded", "action": "conclude_match"}

        # Fielding agent responds to batting decision
        fielding_decision = await self.fielding_agent.recommend_field(
            self.state, batting_decision
        )
        self.state.tokens_used += 120

        # Simulate ball outcomes based on coordination
        runs_this_over = await self._simulate_balls(
            batting_decision, fielding_decision
        )
        self.state.runs += runs_this_over
        self.state.overs += 1

        # Update phase based on overs completed
        if self.state.overs <= 6:
            self.state.current_phase = MatchPhase.POWERPLAY
        elif self.state.overs <= 15:
            self.state.current_phase = MatchPhase.MIDDLE
        else:
            self.state.current_phase = MatchPhase.DEATH

        return {
            "over": self.state.overs,
            "runs_this_over": runs_this_over,
            "total_runs": self.state.runs,
            "batting_strategy": batting_decision["strategy"],
            "field_setup": fielding_decision["field_type"],
            "tokens_remaining": self.state.max_tokens - self.state.tokens_used
        }

    async def _simulate_balls(self, batting: dict, fielding: dict) -> int:
        """Simulate ball outcomes (simplified for demo)."""
        base_score = 4 if batting["strategy"] == "aggressive" else 2
        if fielding["field_type"] == "defensive":
            return base_score + 2  # Better scoring against defensive field
        return base_score

# Production simulation
async def run_cricket_match():
    orchestrator = MatchOrchestrator()
    print("\n🏏 PRODUCTION CRICKET MATCH SIMULATION\n")

    for over_num in range(1, 21):
        result = await orchestrator.execute_over()
        print(f"Over {result['over']:2d}: {result['runs_this_over']} runs | "
              f"Total: {result['total_runs']} | "
              f"Batting: {result['batting_strategy']:10s} | "
              f"Tokens: {result['tokens_remaining']:5d}")

        if result.get('status') == 'token_budget_exceeded':
            print("\n⚠️  TOKEN BUDGET EXCEEDED - Match concluded early!")
            break

        await asyncio.sleep(0.1)  # Simulate I/O delay

    print(f"\n✅ Final Score: {orchestrator.state.runs}/{orchestrator.state.wickets} "
          f"in {orchestrator.state.overs} overs")
    print(f"📊 Tokens Used: {orchestrator.state.tokens_used}/{orchestrator.state.max_tokens}")

# Run with: asyncio.run(run_cricket_match())
